#' MS3 lipids library
#'
#' Returns DataFrame containing all ms3 lipid library information
#'
#' @param ms2_lib
#'     msp lipid library dataframe (can be generated by mzkitcpp::import_msp_lipids_library()).
#'
#' @export
to_ms3_lib <- function(ms2_lib) {
  # Case: input is a data frame.
  is_has_data_frame <- any(class(ms2_lib) == "data.frame")
  if (!is_has_data_frame) {
    stop("Input argument \"ms2_lib\" must be a data frame.\n
         This can be generated by calling mzkitcpp::import_msp_lipids_library(<file-path>).")
  }

  ms3_lib <- ms2_lib %>%
    dplyr::mutate(ref_ms2_mz_prec_str = stringr::str_extract(fragmentLabel, "ms3-\\{[0-9]+\\.[0-9]+\\}")) %>%
    dplyr::mutate(ref_ms2_mz_prec = ifelse(!is.na(ref_ms2_mz_prec_str), gsub("^ms3-\\{", "", ref_ms2_mz_prec_str), "")) %>%
    dplyr::mutate(ref_ms2_mz_prec = ifelse(!is.na(ref_ms2_mz_prec_str), gsub("\\}$", "", ref_ms2_mz_prec), "")) %>%
    dplyr::mutate(ref_ms2_mz_prec = ifelse(!is.na(ref_ms2_mz_prec_str), as.double(ref_ms2_mz_prec), NA)) %>%
    dplyr::filter(!is.na(ref_ms2_mz_prec)) %>%
    dplyr::mutate(prec_mzs = paste0("(", as.character(round(ref_ms1_mz, digits = 0)), ", ", as.character(round(ref_ms2_mz_prec, digits = 0)), ")")) %>%
    dplyr::rename(ref_ms3_mz = ref_ms2_mz) %>%
    dplyr::rename(ref_ms2_mz = ref_ms2_mz_prec) %>%
    dplyr::mutate(ms3_mz_str = as.character(round(ref_ms3_mz))) %>%
    dplyr::select(-ref_ms2_mz_prec_str) %>%
    dplyr::mutate(fragmentLabel = gsub("ms3-\\{[0-9]+\\.[0-9]+\\}[- ]?", "", fragmentLabel)) %>%
    dplyr::mutate(fragment_label_bits = stringr::str_split(fragmentLabel, "/")) %>%
    dplyr::mutate(fragmentLabel = sapply(fragment_label_bits, function(x) {
      x_u <- unique(x)
      x_u_s <- stringr::str_sort(x_u)
      paste(x_u_s, collapse = "/")
    })) %>%
    dplyr::select(-fragment_label_bits) %>%
    # return in reasonable order
    dplyr::select(
      lipidClass,
      compositionSummary,
      chainLengthSummary,
      molecularFormula,
      compoundMonoisotopicMass,
      compoundName,
      adductName,
      fragmentLabel,
      ref_ms1_mz,
      ref_ms2_mz,
      ref_ms3_mz,
      prec_mzs,
      ms3_mz_str
    )

  ms3_lib
}

#' MS2 lipids library
#'
#' Returns DataFrame containing all ms3 lipid library information formatted as an MS2 library
#'
#' @param ms3_lib
#'     msp lipid library dataframe formatted in ms3 format
#'     ms3 libraries can be created from ms2 libraries by clamr::to_ms3(ms2_lib)
#'
#' @export
to_ms2_lib <- function(ms3_lib) {
  ms2_lib <- ms3_lib %>%
    dplyr::mutate(fragmentLabel = paste0("ms3-{", as.character(ref_ms2_mz), "} ", fragmentLabel)) %>%
    dplyr::mutate(ref_ms2_mz = ref_ms3_mz) %>%
    dplyr::select(-ref_ms3_mz)

  ms2_lib
}

#' 13C MS2 lipid library
#'
#' Return a copy of library with a single 12C replaced for 13C in each compound.
#' All relevant columns are adjusted accordingly.
#'
#' @param ms2_lib
#'    msp lipid library dataframe imported via mzkitcpp::import_msp_lipids_library()
#'
#' @export
to_13C_lib <- function(ms2_lib) {
  ms2_13C_lib <- ms2_lib %>%
    dplyr::mutate(ref_ms2_mz = ifelse(ref_ms1_mz == ref_ms2_mz, ref_ms2_mz + 1.00335483521, ref_ms2_mz)) %>%
    dplyr::mutate(ref_ms1_mz = ref_ms1_mz + 1.00335483521) %>%
    dplyr::mutate(compoundName = paste0(compoundName, "_13C")) %>%
    dplyr::mutate(compositionSummary = paste0(compositionSummary, "_13C")) %>%
    dplyr::mutate(chainLengthSummary = paste0(chainLengthSummary, "_13C")) %>%
    dplyr::mutate(compoundMonoisotopicMass = compoundMonoisotopicMass + 1.00335483521)
  ms2_13C_lib
}

#' Chain Length Summary Library
#'
#' Converts a standard imported lipids library to one with a maximum of one
#' compound name per chain length summary.
#' Fragment labels related to sn chains will correspond appropriately with
#' ms2 m/z values.
#'
#' @param ms2_lib
#'     msp lipid library dataframe (can be generated by mzkitcpp::import_msp_lipids_library()).
#'
#' @export
to_one_per_chainLengthSummary <- function(ms2_lib) {
  col_names <- colnames(ms2_lib)

  # TODO: Why was this ever added here?
  # if ("ms2_intensity" %in% col_names) {
  #   ms2_lib <- ms2_lib %>% dplyr::select(-ms2_intensity)
  # }

  if ("prec_mzs" %in% col_names && "ms3_mz_str" %in% colnames(ms2_lib)) {
    # indicates an ms3 lib. multiple ref_ms2_mz values are possible, use ref_ms3_mz instead.

    ms2_lib_one_per_chainLengthSummary <- ms2_lib %>%
      dplyr::group_by(lipidClass, chainLengthSummary, adductName, prec_mzs, ms3_mz_str) %>%
      dplyr::slice(1, .preserve = TRUE) %>%
      dplyr::ungroup()
  } else {
    ms2_lib_one_per_chainLengthSummary <- ms2_lib %>%
      dplyr::group_by(lipidClass, chainLengthSummary, adductName, ref_ms2_mz) %>%
      dplyr::slice(1, .preserve = TRUE) %>%
      dplyr::ungroup()
  }

  ms2_lib_one_per_chainLengthSummary
}

#' Add Direct Infusion Search Results
#'
#' @description
#' Creates an mzrollDB file if it does not already exist. (calls create_mzrolldb)
#' Write the search results into the mzrollDB file as a new table of peak groups.
#' Adjust the Compounds table with all summarized Compounds.
#'
#' @param mzroll_db_path
#'      Absolute file path of mzroll_db_file.
#'      If the file does not yet exist, it will be created
#'
#' @param samples
#'      list of all samples analyzed in the experiment.
#'
#' @param ms2_ranges
#'      ms2_ranges used to generate di_search_results.
#'      Needed to properly determine composition of summarized compounds.
#'
#' @param library_name
#'      Name of library used to carry out search (msp file).
#'      This file should be imported into maven prior to opening mzrollDB file.
#'
#' @param search_lib_sliced
#'      Search library used to generate di_search_results.
#'      Needed to properly determine composition of summarized compounds.
#'
#' @param search_params
#'      list of parameter values used in search.
#'      If a parameter is not included in the list, use the default value.
#'      Empty list for default values.
#'
#' @param adducts_file
#'      adducts_file used to generate di_search_results.
#'      Needed to properly determine composition of summarized compounds.
#'
#' @param di_search_results
#'      search results from DIMS search.
#'
#' @param di_quant_ions
#'      hierarchical quant ions from DIMS search.
#'      A modification of the DIMS search adduct table, containing
#'      hierarchical ms1 intensity, hierarchical ms2 intensity, diagnostic ms2 intensity,
#'      nearest scan normalized ms1 intensity.
#'
#' @param set_name
#'      vector of designations to apply to each sample.
#'      if NULL or invalid, all samples will be in set "A".
#'
#' @param color_table
#'      tibble of pre-specified colors for samples.
#'      requires a tibble with numeric columns "red", "green", and "blue" and character column "sample_name"
#'      If the color_table has the sample_name, sample will receive that color. Otherwise, fall back to default algorithm.
#'
#' @param ui_options list of encoded UI options interpreted by MAVEN
#' @param verbose Print detailed messages/output if set to TRUE. default is TRUE.
#'
#' @export
add_direct_infusion_search_results <- function(mzroll_db_path,
                                               samples,
                                               ms2_ranges,
                                               library_name,
                                               search_lib_sliced,
                                               search_params,
                                               adducts_file,
                                               di_search_results,
                                               di_quant_ions,
                                               set_name = NULL,
                                               color_table = NULL,
                                               ui_options = NULL,
                                               verbose = TRUE) {
  mzroll_db_con <- open_mzrolldb(mzroll_db_path)

  # save search params
  search_name <- mzrolldb_next_search_name(mzroll_db_con, "Direct Infusion Analysis")
  search_params_tbl <- mzkitcpp::DI_encoded_search_params(search_params)

  DBI::dbAppendTable(mzroll_db_con, "search_params", tibble::tibble("searchTableName" = search_name, "parameters" = search_params_tbl))

  # ui options
  if (!is.null(ui_options)) {
    DBI::dbAppendTable(mzroll_db_con, "ui", ui_options)
  }

  if (verbose) {
    cat(paste0("Search results saved to mzrollDB as \"", search_name, "\".\n"))
  }

  # save summarized compounds
  compound_table <- create_compound_table(di_search_results, search_lib_sliced, ms2_ranges, adducts_file)

  if (nrow(compound_table) > 0) {
    DBI::dbAppendTable(mzroll_db_con, "compounds", compound_table)
    if (verbose) {
      cat(paste0("Saved ", nrow(compound_table), " summarized compounds to mzrollDB.\n"))
    }
  }

  # add samples to possible existing samples information, retrieve all samples information as data frame
  samples_tbl <- get_samples_table(mzroll_db_con, samples, set_name, color_table)

  # save peakgroups + peaks
  add_DIMS_peakgroups_and_peaks(
    mzroll_db_con,
    di_search_results,
    di_quant_ions,
    ms2_ranges,
    samples_tbl,
    library_name,
    search_name,
    verbose
  )

  DBI::dbDisconnect(mzroll_db_con)
}

